            codeExample: '// Dynamic Array (ArrayList) push_back:\n// Most inserts: O(1)\n// When full: resize O(n), but doubles size\n// Amortized: O(1) per insert\n\nclass DynamicArray {\n  constructor() {\n    this.data = new Array(1);\n    this.size = 0;\n  }\n\n  push(val) {\n    if (this.size === this.data.length) {\n      // Double capacity (O(n) but rare)\n      const newData = new Array(this.data.length * 2);\n      for (let i = 0; i < this.size; i++) {\n        newData[i] = this.data[i];\n      }\n      this.data = newData;\n    }\n    this.data[this.size++] = val;\n  }\n}\n\n// Aggregate method: sum costs / n\n// Accounting method: credit for cheap ops\n// Potential method: energy function',
