            codeExample: '#include <stdio.h>\n\nvoid process(int n) {\n    // VLA - size determined at runtime\n    int arr[n];\n\n    for (int i = 0; i < n; i++) {\n        arr[i] = i * i;\n    }\n\n    for (int i = 0; i < n; i++) {\n        printf("%d ", arr[i]);\n    }\n    printf("\\n");\n}\n\nint main() {\n    process(5);  // arr has 5 elements\n    process(10); // arr has 10 elements\n    return 0;\n}\n\n// Multi-dimensional VLA\nvoid matrix(int rows, int cols, int data[rows][cols]) {\n    for (int i = 0; i < rows; i++) {\n        for (int j = 0; j < cols; j++) {\n            printf("%d ", data[i][j]);\n        }\n        printf("\\n");\n    }\n}\n\n// Note: VLAs are optional in C11 (implementation-defined)',
