            codeExample: '#include <stdio.h>\n\n// Function pointer type\ntypedef int (*operation)(int, int);\n\nint add(int a, int b) { return a + b; }\nint sub(int a, int b) { return a - b; }\nint mul(int a, int b) { return a * b; }\n\nint calculate(operation op, int x, int y) {\n    return op(x, y);\n}\n\nint main() {\n    operation ops[] = {add, sub, mul};\n\n    // Call via function pointer\n    int result = calculate(add, 10, 5);\n    printf("Add: %d\\n", result);\n\n    // Dispatch table\n    for (int i = 0; i < 3; i++) {\n        printf("Result %d: %d\\n", i, ops[i](10, 5));\n    }\n\n    // qsort with custom comparator\n    int arr[] = {5, 2, 8, 1, 9};\n    qsort(arr, 5, sizeof(int), (int (*)(const void*, const void*))add);\n\n    return 0;\n}',
