            codeExample: 'import pandas as pd\n\n# Create datetime index\nidx = pd.date_range("2024-01-01", periods=100, freq="D")\ndf = pd.DataFrame({"value": range(100)}, index=idx)\n\n# Resampling\ndf.resample("W").mean()      # weekly\ndf.resample("M").sum()       # monthly\ndf.resample("Q").agg(["mean", "std"])  # quarterly\n\n# Shifting\nreturns = df["value"].pct_change()\ndf["lag_1"] = df["value"].shift(1)\n\n# Rolling windows\nrolling = df["value"].rolling(window=7)\ndf["rolling_avg"] = rolling.mean()\ndf["rolling_std"] = rolling.std()\n\n# Date features\ndf["year"] = df.index.year\ndf["month"] = df.index.month\ndf["day_of_week"] = df.index.dayofweek\ndf["is_weekend"] = df.index.dayofweek >= 5\n\n# Timezone\nimport pytz\ndf.tz_localize("UTC").tz_convert("US/Eastern")',
